# Create a Global Accelerator for a global API
resource "aws_globalaccelerator_accelerator" "api" {
  name            = "global-api"
  ip_address_type = "IPV4"
  enabled         = true
}

resource "aws_globalaccelerator_listener" "tcp" {
  accelerator_arn = aws_globalaccelerator_accelerator.api.id
  protocol        = "TCP"
  port_range {
    from_port = 443
    to_port   = 443
  }
}

# Endpoint group in primary region
resource "aws_globalaccelerator_endpoint_group" "primary" {
  listener_arn          = aws_globalaccelerator_listener.tcp.id
  endpoint_group_region = "us-east-1"
  traffic_dial_percentage = 100

  endpoint_configuration {
    endpoint_id = aws_lb.api.arn
    weight      = 128
  }
}

# Failover endpoint group in secondary region
resource "aws_globalaccelerator_endpoint_group" "failover" {
  listener_arn          = aws_globalaccelerator_listener.tcp.id
  endpoint_group_region = "eu-west-1"
  traffic_dial_percentage = 0   # Standby — receives traffic if primary fails
  endpoint_configuration {
    endpoint_id = aws_lb.api_eu.arn
    weight      = 128
  }
}

# CloudWatch Internet Monitor — track internet health for your users
resource "aws_internetmonitor_monitor" "prod" {
  monitor_name = "prod-internet-health"
  status       = "ACTIVE"
  traffic_percentage_to_monitor = 25  # Sample 25% of traffic
  max_city_networks_to_monitor  = 500

  internet_measurements_log_delivery {
    s3_config {
      bucket_name = aws_s3_bucket.logs.bucket
      bucket_prefix = "internet-monitor"
    }
  }
}

# Peer TGW in us-east-1 with one in eu-west-1
resource "aws_ec2_transit_gateway_peering_attachment" "us_eu" {
  transit_gateway_id      = aws_ec2_transit_gateway.us.id
  peer_transit_gateway_id = aws_ec2_transit_gateway.eu.id
  peer_region             = "eu-west-1"
  tags = { Name = "us-east-1-to-eu-west-1" }
}

# Accept on the EU side (separate provider)
resource "aws_ec2_transit_gateway_peering_attachment_accepter" "eu_accept" {
  provider                                = aws.eu
  transit_gateway_attachment_id           = aws_ec2_transit_gateway_peering_attachment.us_eu.id
  tags = { Name = "eu-accept" }
}

# Static route: EU-bound traffic via peering
resource "aws_ec2_transit_gateway_route" "to_eu" {
  destination_cidr_block         = "10.2.0.0/16"
  transit_gateway_route_table_id = aws_ec2_transit_gateway.us.association_default_route_table_id
  transit_gateway_attachment_id  = aws_ec2_transit_gateway_peering_attachment.us_eu.id
}

# Enable MACsec on a Direct Connect connection
resource "aws_dx_connection" "my_dx" {
  name            = "corp-to-aws"
  bandwidth       = "10Gbps"
  location        = "EqDC2"
  request_macsec  = true
}

# Associate a MACsec CKN/CAK secret
resource "aws_dx_macsec_key_association" "key" {
  connection_id = aws_dx_connection.my_dx.id
  ckn           = var.macsec_ckn
  cak           = var.macsec_cak
}
